import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const ProgrammeMaster = () => {
    const [programmes, setProgrammes] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ department: '', programme: '', programmeShortName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchProgrammes();
        fetchDepartments();
    }, []);

    const fetchProgrammes = async () => {
        try {
            const { data } = await API.get('/master/programme');
            setProgrammes(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching programmes' });
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching departments' });
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/programme', formData);
            setFormData({ department: '', programme: '', programmeShortName: '' });
            fetchProgrammes();
            setMessage({ type: 'success', text: '✓ Programme added successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error adding programme' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>📚 Programme Master</h1>
                    <p style={styles.subtitle}>Manage all academic programmes</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' 
                            ? 'rgba(16, 185, 129, 0.2)' 
                            : 'rgba(239, 68, 68, 0.2)',
                        borderColor: message.type === 'success' ? '#10b981' : '#ef4444',
                        color: message.type === 'success' ? '#a7f3d0' : '#fca5a5',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.container}>
                    <div style={styles.formSide}>
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Department</label>
                                <select 
                                    required
                                    value={formData.department}
                                    onChange={e => setFormData({...formData, department: e.target.value})}
                                    style={styles.input}
                                >
                                    <option value="">Select Department</option>
                                    {departments.map(dept => (
                                        <option key={dept._id} value={dept._id}>{dept.department}</option>
                                    ))}
                                </select>
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Programme Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.programme}
                                    onChange={e => setFormData({...formData, programme: e.target.value})}
                                    style={styles.input}
                                    placeholder="Enter programme name..."
                                />
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Short Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.programmeShortName}
                                    onChange={e => setFormData({...formData, programmeShortName: e.target.value})}
                                    style={styles.input}
                                    placeholder="e.g., BCA, MCA..."
                                    maxLength="5"
                                />
                            </div>

                            <button type="submit" disabled={loading} style={{...styles.button, opacity: loading ? 0.6 : 1}}>
                                {loading ? '⏳ Adding...' : '➕ Add Programme'}
                            </button>
                        </form>
                    </div>

                    <div style={styles.tableSide}>
                        <h3 style={styles.tableTitle}>📋 Programme List</h3>
                        <div style={styles.tableContainer}>
                            <table style={styles.table}>
                                <thead>
                                    <tr style={styles.tableHeaderRow}>
                                        <th style={{...styles.tableHeader, width: '40%'}}>Department</th>
                                        <th style={{...styles.tableHeader, width: '35%'}}>Programme Name</th>
                                        <th style={{...styles.tableHeader, width: '25%'}}>Short Name</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {programmes.length > 0 ? (
                                        programmes.map((prog, idx) => (
                                            <tr key={prog._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                <td style={styles.tableCell}>{prog.department?.department}</td>
                                                <td style={styles.tableCell}>{prog.programme}</td>
                                                <td style={{...styles.tableCell, textAlign: 'center'}}>
                                                    <span style={styles.badge}>{prog.programmeShortName}</span>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr>
                                            <td colSpan="3" style={{...styles.tableCell, textAlign: 'center', color: '#94a3b8'}}>
                                                No programmes found
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const styles = {
    pageWrapper: {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
        color: '#e0e7ff',
        fontFamily: "'Poppins', sans-serif",
    },
    contentArea: {
        maxWidth: '1400px',
        margin: '0 auto',
        padding: '40px 30px',
    },
    headerSection: {
        marginBottom: '40px',
    },
    mainTitle: {
        fontSize: '2.2rem',
        fontWeight: 800,
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        marginBottom: '10px',
    },
    subtitle: {
        fontSize: '1rem',
        color: '#94a3b8',
        fontWeight: 500,
    },
    alertBox: {
        padding: '16px 20px',
        borderRadius: '12px',
        border: '2px solid',
        marginBottom: '30px',
        fontWeight: 600,
    },
    container: {
        display: 'grid',
        gridTemplateColumns: '1fr 1.5fr',
        gap: '30px',
        alignItems: 'start',
    },
    formSide: {
        background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))',
        backdropFilter: 'blur(15px)',
        border: '2px solid rgba(51, 65, 85, 0.3)',
        borderRadius: '16px',
        padding: '28px',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
    },
    form: {
        display: 'flex',
        flexDirection: 'column',
        gap: '20px',
    },
    formGroup: {
        display: 'flex',
        flexDirection: 'column',
    },
    label: {
        fontSize: '0.95rem',
        fontWeight: 600,
        color: '#cbd5e1',
        marginBottom: '8px',
        letterSpacing: '0.3px',
    },
    input: {
